// app/page.tsx
import { revalidateTag, unstable_cache } from "next/cache";
import { getAllProducts } from "@/lib/db";

const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ["products"],
  { tags: ["products"] },
);

export default async function Page() {
  async function syncProducts() {
    "use server";

    // Keep the current catalog usable while the next read refreshes the cache.
    revalidateTag("products", "max");
  }

  const products = await getCachedProducts();

  return (
    <main className="catalog-shell">
      <header className="catalog-header">
        <div>
          <p className="eyebrow">Commerce operations</p>
          <h1>Product catalog</h1>
          <p className="catalog-summary">
            Browse pricing, inventory, and availability across your catalog.
          </p>
        </div>
        <form action={syncProducts}>
          <button type="submit">Sync latest catalog</button>
        </form>
      </header>

      <section className="catalog-section" aria-labelledby="catalog-heading">
        <div className="section-heading">
          <div>
            <h2 id="catalog-heading">All products</h2>
            <p>{products.length} items</p>
          </div>
          <span className="status">Catalog view</span>
        </div>

        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th scope="col">Product</th>
                <th scope="col">SKU</th>
                <th scope="col">Price</th>
                <th scope="col">Availability</th>
              </tr>
            </thead>
            <tbody>
              {products.map((product) => (
                <tr key={product.id}>
                  <td className="product-name">{product.name}</td>
                  <td>SKU-{String(product.id).padStart(4, "0")}</td>
                  <td>${product.price.toFixed(2)}</td>
                  <td><span className="availability">In stock</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </main>
  );
}


